import{_ as d,c as r,o,aj as l}from"./chunks/framework.CynFBi0q.js";const g=JSON.parse('{"title":"第1章 产品经理到底是个啥","description":"","frontmatter":{},"headers":[],"relativePath":"handbook/ai-product/chapter_1.md","filePath":"handbook/ai-product/chapter_1.md","lastUpdated":1782008855000}'),p={name:"handbook/ai-product/chapter_1.md"};function a(e,t,n,i,h,s){return o(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="第1章-产品经理到底是个啥" tabindex="-1">第1章 产品经理到底是个啥 <a class="header-anchor" href="#第1章-产品经理到底是个啥" aria-label="Permalink to “第1章 产品经理到底是个啥”">​</a></h1><p>你以为产品经理就是画原型的？做了3年才知道，画原型只是产品经理工作中不到10%的环节。真正拉开差距的，是那90%看不见的思考。</p><p>我是怕浪猫，一个从代码堆里爬出来、在产品坑里摸爬滚打多年的老兵。这个系列，我准备把产品经理从0到1的所有核心能力，一次性讲透。</p><h2 id="_1-1-互联网与互联网产品" tabindex="-1">1.1 互联网与互联网产品 <a class="header-anchor" href="#_1-1-互联网与互联网产品" aria-label="Permalink to “1.1 互联网与互联网产品”">​</a></h2><h3 id="_1-1-1-互联网行业概览与发展脉络" tabindex="-1">1.1.1 互联网行业概览与发展脉络 <a class="header-anchor" href="#_1-1-1-互联网行业概览与发展脉络" aria-label="Permalink to “1.1.1 互联网行业概览与发展脉络”">​</a></h3><p>要理解产品经理，先得理解互联网行业本身。</p><p>互联网行业的发展可以用三个阶段来概括：</p><p><strong>第一阶段：信息互联网（1995-2008）</strong></p><p>这个阶段的互联网本质是&quot;信息搬运工&quot;。新浪把新闻搬上网，搜狐把分类信息搬上网，百度把搜索搬到线上。核心逻辑是：线下有什么，线上就有什么。产品形态以门户网站、搜索引擎、BBS为主，商业模式主要是广告。</p><p>这个阶段的产品经理，更像是&quot;内容编辑&quot;——决定页面放什么内容、怎么排列、用户往哪看。技术门槛低，但信息组织能力要求高。</p><p><strong>第二阶段：消费互联网（2008-2018）</strong></p><p>智能手机普及后，互联网从PC端走向移动端，从&quot;信息获取&quot;变成&quot;生活服务&quot;。淘宝让你不用逛街就能购物，微信让你不用见面就能社交，美团让你不用出门就能吃饭。核心逻辑是：线下有什么体验，线上就替代什么体验。</p><p>这个阶段的产品经理数量井喷，因为每多一个App，就多出几个产品经理的坑。2015年前后，&quot;人人都是产品经理&quot;这句话被喊得震天响。</p><p><strong>第三阶段：产业互联网（2018至今）</strong></p><p>消费互联网的流量红利见顶后，互联网开始向产业深处渗透。不是做个App替代线下，而是用数据和技术重构整个产业链。智能制造、数字医疗、智慧城市，都是这个阶段的产物。同时，AI的爆发让&quot;产品经理&quot;这个角色再次被重新定义。</p><blockquote><p>互联网的每次进化，都不是简单的技术升级，而是对人类协作方式的根本重构。产品经理的价值，恰恰在于理解这种重构，并在其中找到自己的位置。</p></blockquote><p><strong>互联网行业现状一览</strong></p><table tabindex="0"><thead><tr><th>维度</th><th>现状</th><th>趋势</th></tr></thead><tbody><tr><td>用户规模</td><td>中国网民超10亿</td><td>增速放缓，存量竞争</td></tr><tr><td>商业模式</td><td>广告/电商/游戏/订阅</td><td>混合模式增多</td></tr><tr><td>竞争格局</td><td>头部集中，尾部长尾</td><td>中小公司差异化求生</td></tr><tr><td>技术驱动</td><td>AI/大数据/云计算</td><td>从工具到基础设施</td></tr><tr><td>人才需求</td><td>产品经理岗位萎缩</td><td>高端产品经理更稀缺</td></tr></tbody></table><h3 id="_1-1-2-互联网产品的定义与特征" tabindex="-1">1.1.2 互联网产品的定义与特征 <a class="header-anchor" href="#_1-1-2-互联网产品的定义与特征" aria-label="Permalink to “1.1.2 互联网产品的定义与特征”">​</a></h3><p>什么是互联网产品？很多人会说&quot;就是App&quot;，但这个回答太窄了。</p><p>互联网产品是：<strong>通过互联网技术，为特定用户群体解决特定问题，并创造商业价值的解决方案。</strong></p><p>这个定义里有四个关键词：</p><p><strong>特定用户群体</strong>——产品不是给所有人用的。微信给社交用户用，钉钉给办公用户用，即便都是即时通讯，用户群体完全不同。产品经理最重要的决策之一，就是&quot;不做谁的生意&quot;。</p><p><strong>特定问题</strong>——产品解决的是问题，不是需求。用户说&quot;我想要一匹更快的马&quot;，需求是更快的马，问题是出行效率。产品经理要穿透需求，看到问题。</p><p><strong>互联网技术</strong>——技术是手段，不是目的。用户不在乎你用的是什么架构，在乎的是问题有没有被解决。但产品经理必须理解技术的能力边界，否则设计出来的方案要么做不出来，要么成本失控。</p><p><strong>商业价值</strong>——没有商业价值的产品是公益项目。产品经理不是理想主义者，必须在用户价值和商业价值之间找到平衡。</p><p>互联网产品有五个核心特征：</p><p><strong>第一，网络效应。</strong> 用户越多，产品越有价值。微信一个人用没意义，十亿人用才有意义。产品经理需要思考：我的产品有没有网络效应？如何设计机制让网络效应更快显现？</p><p><strong>第二，边际成本递减。</strong> 多服务一个用户的成本几乎为零。这意味着互联网产品天然追求规模，而产品经理需要在规模和体验之间做权衡。</p><p><strong>第三，快速迭代。</strong> 传统产品上市后再改很难，互联网产品可以每天发版。快速迭代不是乱改，而是基于数据和反馈的持续优化。</p><p><strong>第四，数据驱动。</strong> 一切可测量，一切可优化。产品经理必须学会用数据说话，而不是凭直觉决策。</p><p><strong>第五，平台化趋势。</strong> 优秀的产品会从工具变成平台。微信从通讯工具变成社交平台，淘宝从电商工具变成交易平台。产品经理需要思考：我的产品有没有平台化的可能？</p><blockquote><p>产品不是功能堆砌，而是问题的最优解。功能多不等于产品好，能精准解决问题才是好产品。</p></blockquote><h3 id="_1-1-3-互联网产品的类型与分类" tabindex="-1">1.1.3 互联网产品的类型与分类 <a class="header-anchor" href="#_1-1-3-互联网产品的类型与分类" aria-label="Permalink to “1.1.3 互联网产品的类型与分类”">​</a></h3><p>理解产品类型，是产品经理的基本功。不同类型的产品，设计思路、核心指标、商业模式完全不同。</p><p><strong>按用户类型分</strong></p><table tabindex="0"><thead><tr><th>类型</th><th>典型产品</th><th>核心关注</th><th>关键指标</th></tr></thead><tbody><tr><td>C端产品</td><td>微信、抖音、淘宝</td><td>用户体验、增长</td><td>DAU、留存率、时长</td></tr><tr><td>B端产品</td><td>钉钉、飞书、Salesforce</td><td>效率、流程</td><td>续费率、NPS、使用率</td></tr><tr><td>平台产品</td><td>淘宝、美团、滴滴</td><td>生态平衡</td><td>GMV、供需比、匹配效率</td></tr></tbody></table><p><strong>按业务形态分</strong></p><table tabindex="0"><thead><tr><th>类型</th><th>典型产品</th><th>核心逻辑</th><th>变现方式</th></tr></thead><tbody><tr><td>工具型</td><td>美图、WPS、剪映</td><td>用完即走，提高效率</td><td>增值服务/订阅</td></tr><tr><td>内容型</td><td>抖音、B站、知乎</td><td>内容消费，时长为王</td><td>广告/会员/打赏</td></tr><tr><td>社交型</td><td>微信、微博、Soul</td><td>人与人连接</td><td>广告/游戏/增值</td></tr><tr><td>交易型</td><td>淘宝、京东、拼多多</td><td>商品/服务交易</td><td>佣金/广告/金融</td></tr><tr><td>平台型</td><td>美团、滴滴、 Airbnb</td><td>供需匹配</td><td>佣金/广告</td></tr></tbody></table><p><strong>按产品阶段分</strong></p><table tabindex="0"><thead><tr><th>阶段</th><th>特征</th><th>产品经理重点</th></tr></thead><tbody><tr><td>探索期</td><td>PMF未验证</td><td>快速试错，找方向</td></tr><tr><td>成长期</td><td>PMF已验证，高速增长</td><td>增长策略，体验优化</td></tr><tr><td>成熟期</td><td>增长放缓，竞争激烈</td><td>精细化运营，商业化</td></tr><tr><td>衰退期</td><td>用户流失，市场萎缩</td><td>转型或收缩，延长生命周期</td></tr></tbody></table><blockquote><p>看懂产品类型，比看懂功能列表重要一百倍。类型决定了你的设计思路、指标体系和商业模式。</p></blockquote><h2 id="_1-2-产品经理的角色与职责" tabindex="-1">1.2 产品经理的角色与职责 <a class="header-anchor" href="#_1-2-产品经理的角色与职责" aria-label="Permalink to “1.2 产品经理的角色与职责”">​</a></h2><h3 id="_1-2-1-产品经理的起源与角色定位" tabindex="-1">1.2.1 产品经理的起源与角色定位 <a class="header-anchor" href="#_1-2-1-产品经理的起源与角色定位" aria-label="Permalink to “1.2.1 产品经理的起源与角色定位”">​</a></h3><p>产品经理这个角色，最早来自宝洁。1931年，宝洁的Neil McElroy写了一份著名的备忘录，提出&quot;Brand Man&quot;（品牌经理）的概念——一个人对品牌的整体表现负责，从市场调研到产品开发到销售推广。</p><p>互联网行业的产品经理，继承了这种&quot;端到端负责&quot;的精神，但工作内容完全不同。宝洁的品牌经理管的是实体产品的全生命周期，互联网产品经理管的是数字产品的全生命周期。</p><p>在中国互联网，产品经理角色的演化经历了几个阶段：</p><p><strong>2010年前后：运营型产品经理。</strong> 这个阶段产品经理大量来自运营转岗，核心能力是&quot;管需求&quot;——运营提什么需求，产品经理就写什么PRD，研发就做什么功能。</p><p><strong>2015年前后：设计型产品经理。</strong> 移动互联网爆发，交互设计成为核心竞争力。这个阶段的产品经理要会画原型、写PRD、做竞品分析，核心竞争力是&quot;把功能设计好&quot;。</p><p><strong>2019年前后：数据型产品经理。</strong> 增长黑客概念兴起，产品经理必须懂数据。A/B测试、漏斗分析、留存模型成为基本技能。</p><p><strong>2023年前后：AI型产品经理。</strong> 大模型爆发后，产品经理需要理解AI的能力边界，设计AI驱动的产品体验。提示词工程、RAG、Agent成为新的核心技能。</p><p>产品经理的角色定位，本质上是一个<strong>&quot;翻译器&quot;</strong>：</p><ul><li>把用户需求翻译成产品方案</li><li>把商业目标翻译成功能设计</li><li>把技术约束翻译成体验取舍</li><li>把数据洞察翻译成迭代方向</li></ul><blockquote><p>产品经理不是决策者，而是&quot;最佳方案的发现者和推动者&quot;。你的权力不是来自职位，而是来自判断力。</p></blockquote><h3 id="_1-2-2-产品经理的核心职责边界" tabindex="-1">1.2.2 产品经理的核心职责边界 <a class="header-anchor" href="#_1-2-2-产品经理的核心职责边界" aria-label="Permalink to “1.2.2 产品经理的核心职责边界”">​</a></h3><p>产品经理到底负责什么？这个问题看似简单，实际上很多人搞不清楚。</p><p>我把产品经理的职责分为三个层次：</p><p><strong>第一层：必须做（核心职责）</strong></p><table tabindex="0"><thead><tr><th>职责</th><th>说明</th><th>产出物</th></tr></thead><tbody><tr><td>需求分析</td><td>理解用户真正要什么</td><td>需求文档/用户故事</td></tr><tr><td>产品设计</td><td>把需求变成可落地方案</td><td>原型/PRD/架构图</td></tr><tr><td>项目推进</td><td>确保方案按时按质落地</td><td>排期/进度跟踪/风险应对</td></tr><tr><td>数据驱动</td><td>用数据验证假设、指导迭代</td><td>数据分析报告/A/B实验</td></tr><tr><td>竞品分析</td><td>理解市场格局和竞争态势</td><td>竞品分析报告</td></tr></tbody></table><p><strong>第二层：应该做（扩展职责）</strong></p><table tabindex="0"><thead><tr><th>职责</th><th>说明</th></tr></thead><tbody><tr><td>用户调研</td><td>深入一线，获取一手用户反馈</td></tr><tr><td>商业分析</td><td>理解商业模式，参与收入规划</td></tr><tr><td>技术评估</td><td>理解技术方案，参与技术选型</td></tr><tr><td>团队建设</td><td>培养新人，建设产品文化</td></tr></tbody></table><p><strong>第三层：可以不做（边界外）</strong></p><table tabindex="0"><thead><tr><th>职责</th><th>说明</th></tr></thead><tbody><tr><td>项目管理</td><td>有专业项目经理时，不必兼任</td></tr><tr><td>UI设计</td><td>有设计师时，只提供设计方向</td></tr><tr><td>代码开发</td><td>理解但不亲自写</td></tr><tr><td>运营推广</td><td>提供策略但不执行</td></tr></tbody></table><p>关键原则：<strong>产品经理对结果负责，但不负责所有过程。</strong> 你的核心价值是&quot;做正确的决定&quot;，而不是&quot;做所有的事情&quot;。</p><blockquote><p>职责边界不是用岗位说明书划定的，而是用你的判断力划定的。该你做的你推不掉，不该你做的你抢不来。</p></blockquote><h3 id="_1-2-3-产品经理与上下游角色的协作关系" tabindex="-1">1.2.3 产品经理与上下游角色的协作关系 <a class="header-anchor" href="#_1-2-3-产品经理与上下游角色的协作关系" aria-label="Permalink to “1.2.3 产品经理与上下游角色的协作关系”">​</a></h3><p>产品经理不是一个人在战斗。理解上下游角色的诉求，是高效协作的前提。</p><p><strong>产品经理 vs 研发</strong></p><p>这是最常见的协作关系，也是最容易出现摩擦的。</p><p>研发的视角：产品经理的需求总是变来变去，写的PRD有逻辑漏洞，还总想加需求。</p><p>产品经理的视角：研发总说&quot;做不了&quot;，技术方案不够灵活，排期总是拖。</p><p>怎么办？三个原则：</p><ol><li><strong>需求评审前先技术预沟通</strong>。别在评审会上被技术一问三不知，提前和技术负责人对齐方案可行性。</li><li><strong>写清楚&quot;为什么做&quot;，不只是&quot;做什么&quot;</strong>。研发理解了背景，才能给出更好的技术方案。</li><li><strong>尊重技术评估，但不盲从</strong>。有时候&quot;做不了&quot;是真的做不了，有时候是&quot;不想做&quot;。区分这两者需要你有一定的技术理解力。</li></ol><p><strong>产品经理 vs 设计</strong></p><p>设计的视角：产品经理给的空间太小，交互逻辑不清晰，总是改来改去。</p><p>产品经理的视角：设计太追求好看，忽略了效率和可用性。</p><p>协作要点：</p><ol><li><strong>先对齐交互逻辑，再开始视觉设计</strong>。避免设计稿出来后发现流程不对。</li><li><strong>给设计目标，不给设计方案</strong>。&quot;提升转化率&quot;比&quot;把按钮放大&quot;更好。</li><li><strong>评审时关注用户体验，不关注审美偏好</strong>。你可以说&quot;这个操作路径太长&quot;，但别说&quot;这个颜色不好看&quot;。</li></ol><p><strong>产品经理 vs 运营</strong></p><p>运营的视角：产品功能不够灵活，运营工具不好用，数据不支持精细化运营。</p><p>产品经理的视角：运营的需求太碎片化，没有优先级，总想加功能。</p><p>协作要点：</p><ol><li><strong>定期对齐运营目标和产品节奏</strong>。运营追求短期效果，产品追求长期价值，需要找到平衡。</li><li><strong>建设运营工具体系</strong>。好的运营工具可以减少80%的定制化需求。</li><li><strong>数据共享</strong>。让运营看到产品数据，让产品看到运营数据，信息对称才能决策同步。</li></ol><p><strong>产品经理 vs 老板</strong></p><p>老板的视角：我要这个功能，竞品有了我们也要有，这个月必须上线。</p><p>产品经理的视角：老板不懂产品，需求没逻辑，排期不合理。</p><p>协作要点：</p><ol><li><strong>向上管理是产品经理的必修课</strong>。不是所有老板的需求都要照做，但也不能硬顶。</li><li><strong>用数据说话</strong>。&quot;老板，上个月我们做了类似的功能，数据表明效果不好&quot;比&quot;我觉得不行&quot;有说服力一百倍。</li><li><strong>给出替代方案</strong>。拒绝的时候一定附带更好的方案，否则你只是个抱怨者。</li></ol><table tabindex="0"><thead><tr><th>协作对象</th><th>核心矛盾</th><th>解决原则</th></tr></thead><tbody><tr><td>研发</td><td>需求变更vs技术实现</td><td>提前沟通、写清背景、尊重评估</td></tr><tr><td>设计</td><td>美观vs可用</td><td>目标驱动、先交互后视觉</td></tr><tr><td>运营</td><td>短期效果vs长期价值</td><td>对齐目标、工具赋能、数据共享</td></tr><tr><td>老板</td><td>拍脑袋vs数据驱动</td><td>数据说话、替代方案、向上管理</td></tr></tbody></table><blockquote><p>产品经理的核心能力不是&quot;说服所有人&quot;，而是&quot;让所有人朝着同一个方向走&quot;。方向对了，速度才有意义。</p></blockquote><h2 id="_1-3-产品经理如何工作" tabindex="-1">1.3 产品经理如何工作 <a class="header-anchor" href="#_1-3-产品经理如何工作" aria-label="Permalink to “1.3 产品经理如何工作”">​</a></h2><h3 id="_1-3-1-产品从0到1的全流程概览" tabindex="-1">1.3.1 产品从0到1的全流程概览 <a class="header-anchor" href="#_1-3-1-产品从0到1的全流程概览" aria-label="Permalink to “1.3.1 产品从0到1的全流程概览”">​</a></h3><p>一个产品从想法到上线，经历哪些阶段？我用一个完整的流程图来说明：</p><p><strong>第一阶段：发现（Discovery）</strong></p><ul><li>市场调研：行业规模、竞争格局、用户痛点</li><li>用户调研：访谈、问卷、数据观察</li><li>需求定义：核心用户是谁、核心问题是什么、核心场景在哪里</li></ul><p>这个阶段的产出：产品定位文档。</p><p><strong>第二阶段：定义（Definition）</strong></p><ul><li>产品规划：Roadmap、版本规划、优先级</li><li>产品设计：信息架构、功能架构、交互原型</li><li>需求文档：PRD、技术方案、设计规范</li></ul><p>这个阶段的产出：完整的产品方案。</p><p><strong>第三阶段：开发（Development）</strong></p><ul><li>需求评审：和研发、设计、测试对齐方案</li><li>开发跟进：解决开发中的疑问、调整方案</li><li>测试验收：确保实现符合设计</li></ul><p>这个阶段的产出：可上线的代码。</p><p><strong>第四阶段：发布（Launch）</strong></p><ul><li>发布计划：灰度策略、监控指标、回滚方案</li><li>上线执行：按计划发布、监控数据</li><li>紧急响应：处理上线后的紧急问题</li></ul><p>这个阶段的产出：线上产品。</p><p><strong>第五阶段：迭代（Iteration）</strong></p><ul><li>数据分析：核心指标、用户反馈、功能使用率</li><li>问题诊断：哪些功能好用、哪些不好用、为什么</li><li>下一版规划：新需求、优化点、技术债务</li></ul><p>这个阶段的产出：下一版本的需求池。</p><blockquote><p>产品不是&quot;做完&quot;的，是&quot;迭代&quot;出来的。从0到1只是起点，从1到N才是真正的考验。</p></blockquote><p><strong>产品从0到1全流程速查表</strong></p><table tabindex="0"><thead><tr><th>阶段</th><th>核心任务</th><th>关键产出</th><th>参与角色</th></tr></thead><tbody><tr><td>发现</td><td>市场调研、用户调研</td><td>产品定位</td><td>PM、用研</td></tr><tr><td>定义</td><td>产品规划、设计、PRD</td><td>产品方案</td><td>PM、设计</td></tr><tr><td>开发</td><td>需求评审、开发跟进、测试</td><td>可上线代码</td><td>PM、研发、测试</td></tr><tr><td>发布</td><td>发布计划、上线、监控</td><td>线上产品</td><td>PM、研发、运营</td></tr><tr><td>迭代</td><td>数据分析、问题诊断、规划</td><td>需求池</td><td>PM、数据、运营</td></tr></tbody></table><h3 id="_1-3-2-产品经理日常工作节奏与节奏感" tabindex="-1">1.3.2 产品经理日常工作节奏与节奏感 <a class="header-anchor" href="#_1-3-2-产品经理日常工作节奏与节奏感" aria-label="Permalink to “1.3.2 产品经理日常工作节奏与节奏感”">​</a></h3><p>产品经理的一天是什么样的？我用一个典型的工作日来说明：</p><p><strong>上午（9:00-12:00）：思考与输出</strong></p><ul><li>9:00-9:30 邮件和消息处理，快速扫一眼昨晚的数据</li><li>9:30-10:30 专注时间：写PRD、画原型、做分析</li><li>10:30-11:00 站会：同步项目进度，暴露风险</li><li>11:00-12:00 需求评审或方案讨论</li></ul><p><strong>下午（13:00-18:00）：沟通与推进</strong></p><ul><li>13:00-14:00 午饭后和同事聊聊天（很多好想法来自非正式沟通）</li><li>14:00-15:30 设计评审或技术方案讨论</li><li>15:30-16:30 用户反馈整理、数据分析</li><li>16:30-17:30 跨部门对齐会</li><li>17:30-18:00 整理今天的工作成果，更新项目文档</li></ul><p><strong>晚上（可选）：深度思考</strong></p><ul><li>20:00-21:00 看行业动态、竞品更新</li><li>21:00-22:00 写周报、整理需求池、规划下周</li></ul><p>这只是&quot;典型&quot;的一天。实际上产品经理的工作节奏有很大的波动性：</p><ul><li>项目启动期：大量会议、频繁沟通</li><li>开发期：相对安静，偶尔处理疑问</li><li>上线期：高度紧张，随时待命</li><li>迭代期：数据分析为主，节奏较缓</li></ul><blockquote><p>产品经理的时间管理不是&quot;把日程排满&quot;，而是&quot;把重要的事排对&quot;。忙不等于有产出，想清楚比做出来更重要。</p></blockquote><p><strong>产品经理时间分配建议</strong></p><table tabindex="0"><thead><tr><th>活动</th><th>建议占比</th><th>说明</th></tr></thead><tbody><tr><td>深度思考与输出</td><td>30%</td><td>写PRD、画原型、做分析</td></tr><tr><td>沟通与协作</td><td>30%</td><td>会议、评审、对齐</td></tr><tr><td>数据与调研</td><td>20%</td><td>数据分析、用户反馈、竞品</td></tr><tr><td>学习与成长</td><td>10%</td><td>行业动态、技术趋势</td></tr><tr><td>行政与事务</td><td>10%</td><td>邮件、文档、流程</td></tr></tbody></table><h3 id="_1-3-3-典型案例-产品经理的工作思考方式" tabindex="-1">1.3.3 典型案例：产品经理的工作思考方式 <a class="header-anchor" href="#_1-3-3-典型案例-产品经理的工作思考方式" aria-label="Permalink to “1.3.3 典型案例：产品经理的工作思考方式”">​</a></h3><p>讲了这么多理论，我用一个真实的场景来展示产品经理是如何思考的。</p><p><strong>场景：老板说&quot;我们也做个社区功能吧&quot;</strong></p><p>普通产品经理的反应：好，我马上去看竞品怎么做，然后画原型写PRD。</p><p>优秀产品经理的反应：先问三个问题——</p><p><strong>问题一：为什么要做？</strong></p><ul><li>老板的判断依据是什么？是看到了竞品在做？是用户在提需求？还是数据表明社区能提升留存？</li><li>不同原因，社区的产品定位完全不同。竞品驱动意味着&quot;防御性功能&quot;，用户驱动意味着&quot;核心功能&quot;，数据驱动意味着&quot;增长手段&quot;。</li></ul><p><strong>问题二：为谁做？</strong></p><ul><li>我们的核心用户是谁？他们有社交需求吗？</li><li>如果核心用户没有社交需求，社区就是一个&quot;伪需求&quot;。工具型产品的社区和内容型产品的社区设计思路完全不同。</li></ul><p><strong>问题三：做成什么样？</strong></p><ul><li>不是先画原型，而是先定义成功指标。社区的北极星指标是什么？是日活跃用户数？是内容生产量？是互动率？</li><li>指标不同，功能设计的优先级就不同。追求内容生产要激励创作者，追求互动要设计推荐机制，追求活跃要营造社区氛围。</li></ul><p>假设经过分析，确定了社区的目标是&quot;提升用户留存&quot;。接下来怎么设计？</p><p><strong>第一步：定义MVP</strong></p><p>社区的最小可用产品是什么？不是功能最全的版本，而是能验证&quot;社区能否提升留存&quot;的最小方案。</p><p>可能的MVP：一个简单的动态流，用户可以发布文字+图片，其他用户可以点赞和评论。仅对部分用户开放。</p><p><strong>第二步：设计核心指标</strong></p><table tabindex="0"><thead><tr><th>指标类型</th><th>指标</th><th>目标</th></tr></thead><tbody><tr><td>北极星</td><td>社区日活用户</td><td>占整体DAU的20%</td></tr><tr><td>过程指标</td><td>发帖率</td><td>日活用户中5%发帖</td></tr><tr><td>过程指标</td><td>互动率</td><td>帖子平均互动数&gt;3</td></tr><tr><td>留存指标</td><td>次日留存</td><td>社区用户比非社区用户高5%</td></tr></tbody></table><p><strong>第三步：定义迭代路径</strong></p><ul><li>V1：基础发帖+评论，验证核心假设</li><li>V2：话题/标签体系，提升内容发现效率</li><li>V3：推荐算法，提升内容匹配效率</li><li>V4：创作者激励，提升内容供给</li></ul><blockquote><p>产品经理的思考方式不是&quot;怎么做&quot;，而是&quot;为什么要做、为谁做、做到什么程度&quot;。想清楚这三个问题，方案自然浮现。</p></blockquote><p><strong>产品经理思考框架3步法</strong></p><table tabindex="0"><thead><tr><th>步骤</th><th>核心问题</th><th>产出</th></tr></thead><tbody><tr><td>为什么做</td><td>背景和目标是什么</td><td>需求定义</td></tr><tr><td>为谁做</td><td>目标用户和场景</td><td>用户画像</td></tr><tr><td>做成什么样</td><td>成功标准和迭代路径</td><td>产品方案</td></tr></tbody></table><hr><p>本章小结：产品经理不是画原型的，不是写文档的，不是开会的。产品经理是&quot;问题的发现者、方案的发现者、结果的推动者&quot;。理解互联网行业、理解产品类型、理解职责边界、理解协作关系，这些是基本功中的基本功。</p><table tabindex="0"><thead><tr><th>本章核心知识点</th><th>一句话总结</th></tr></thead><tbody><tr><td>互联网发展阶段</td><td>信息互联网→消费互联网→产业互联网</td></tr><tr><td>互联网产品定义</td><td>用技术为特定用户解决特定问题并创造价值</td></tr><tr><td>产品经理角色</td><td>翻译器：需求↔方案↔结果</td></tr><tr><td>职责三层模型</td><td>必须做/应该做/可以不做</td></tr><tr><td>协作核心原则</td><td>让所有人朝同一方向走</td></tr><tr><td>工作全流程</td><td>发现→定义→开发→发布→迭代</td></tr><tr><td>思考框架</td><td>为什么做→为谁做→做成什么样</td></tr></tbody></table><p>觉得有用？收藏起来，下次直接照抄。</p><p>你刚入行产品经理时踩过什么坑？评论区说说，怕浪猫帮你复盘。</p><p>关注怕浪猫，下期我们讲&quot;四大核心思维&quot;——用户思维、逻辑思维、管理思维、商业思维，这四个能力决定了你能不能在产品这条路上走远。</p><p>系列进度 1/16</p><p><strong>下章预告：</strong> 第2章，怕浪猫会带你拆解产品经理的四大核心思维。很多人做了三年产品，还在凭直觉做决策，为什么？因为缺的不是经验，是思维框架。下一章，我把这四个框架一次性讲透，让你从&quot;凭感觉做产品&quot;进化到&quot;用思维做产品&quot;。</p>',154)])])}const b=d(p,[["render",a]]);export{g as __pageData,b as default};
